var items = $input.all();
var now = new Date();
var toSend = [];

for (var i = 0; i < items.length; i++) {
  var b = items[i].json;
  if (!b.date || !b.time) continue;
  var meetingDate;
  try {
    var parts = String(b.date).split('/');
    if (parts.length === 3) {
      var mo = parseInt(parts[0]);
      var d = parseInt(parts[1]);
      var y = parseInt(parts[2]);
      var tParts = String(b.time).split(':');
      var h = parseInt(tParts[0]);
      var min = parseInt(tParts[1] || 0);
      meetingDate = new Date(y, mo - 1, d, h, min);
    } else {
      meetingDate = new Date(b.date + ' ' + b.time);
    }
  } catch(e) { continue; }
  if (isNaN(meetingDate.getTime())) continue;
  var diffHrs = (meetingDate - now) / 3600000;
  var sent = (b._reminders_sent || '').split(',').filter(Boolean);
  if (diffHrs >= 156 && diffHrs <= 180 && !sent.includes('7d')) {
    toSend.push(Object.assign({}, b, { _when: '7 days', _type: '7d' }));
  }
  if (diffHrs >= 20 && diffHrs <= 28 && !sent.includes('1d')) {
    toSend.push(Object.assign({}, b, { _when: '1 day', _type: '1d' }));
  }
  if (diffHrs >= 0.5 && diffHrs <= 1.5 && !sent.includes('1h')) {
    toSend.push(Object.assign({}, b, { _when: '1 hour', _type: '1h' }));
  }
}

if (toSend.length === 0) {
  return [];
}
return toSend.map(function(r) { return { json: r }; });

try {
  var webhookItem = $('GLS Form Webhook').all()[0];
  var body = (webhookItem.json.body) || webhookItem.json;
  var slots = $input.all().map(function(i) { return i.json; });

  var salutation = body.salutation || '';
  var givenNames = body.given_names || '';
  var surname = body.surname || '';
  var fullName = [givenNames, surname].filter(Boolean).join(' ') || 'Unknown';
  var email = body.email || '';
  var company = body.company || '';
  var title = body.title || '';
  var topics = body.topics || '';
  var source = body.source || '';
  var slotIdParam = String(body.slot_id || '').trim();
  var preferredDate = String(body.preferred_date || '').trim();
  var preferredTime = String(body.preferred_time || '').replace(/^0/,'').trim();

  var match = null;
  for (var i = 0; i < slots.length; i++) {
    var s = slots[i];
    var sid = String(s.Slot_Id || s.slot_Id || s.slot_id || '');
    if (slotIdParam && sid === slotIdParam) { match = s; break; }
    var slDate = String(s.Date || s.date || '').trim();
    var slTime = String(s.Time || s.time || '').replace(/^0/,'').trim();
    if (!slotIdParam && slDate === preferredDate && slTime === preferredTime) { match = s; break; }
  }

  if (!match) {
    var first = slots.length > 0 ? ('Slot_Id='+String(slots[0].Slot_Id||slots[0].slot_id||'?')+' Date='+String(slots[0].Date||slots[0].date||'?')+' Time='+String(slots[0].Time||slots[0].time||'?')) : 'no_slots';
    return [{ json: { _found: false, _reason: 'nomatch slotId=['+slotIdParam+'] date=['+preferredDate+'] time=['+preferredTime+'] count='+slots.length+' first=['+first+']' } }];
  }

  if (String(match.Status||match.status||'').toLowerCase() !== 'available') {
    return [{ json: { _found: false, _reason: 'not_available status='+String(match.Status||match.status||'') } }];
  }
  var cap = parseInt(match.capacity || 1);
  var cnt = parseInt(match.booked_count || 0);
  if (cnt >= cap) {
    return [{ json: { _found: false, _reason: 'full cnt='+cnt+' cap='+cap } }];
  }

  return [{ json: {
    _found: true,
    slot_id: match.Slot_Id || match.slot_Id || match.slot_id,
    date: match.Date || match.date,
    time: match.Time || match.time,
    slot_capacity: cap,
    slot_booked_count: cnt,
    client_name: fullName,
    email: email,
    company: company,
    title: title,
    booked_at: new Date().toISOString(),
    topics: topics,
    source: source
  } }];
} catch(e) {
  return [{ json: { _found: false, _reason: 'EXCEPTION: ' + e.message } }];
}

var staff = $('Read Staff (Form)').all().map(function(i) { return i.json; });
var bookings = $input.all().map(function(i) { return i.json; });
var formData = $('Match Slot (Form)').all()[0].json;

if (!staff || staff.length === 0) {
  return [{ json: Object.assign({}, formData, { salesperson_name: 'GLS Team', salesperson_email: 'marketing@glshk.com' }) }];
}

var counts = {};
staff.forEach(function(s) { counts[s.salesperson_name] = 0; });
bookings.forEach(function(b) {
  if (b.salesperson_name && counts[b.salesperson_name] !== undefined) counts[b.salesperson_name]++;
});

var assigned = staff[0]; var minCount = Infinity;
staff.forEach(function(s) {
  var c = counts[s.salesperson_name] || 0;
  if (c < minCount) { minCount = c; assigned = s; }
});

return [{ json: {
  slot_id: formData.slot_id, date: formData.date, time: formData.time,
  slot_capacity: formData.slot_capacity || 1,
  slot_booked_count: formData.slot_booked_count || 0,
  client_name: formData.client_name, email: formData.email,
  company: formData.company || '', title: formData.title || '',
  booked_at: formData.booked_at,
  booking_id: Date.now().toString(36) + Math.random().toString(36).substr(2,5),
  salesperson_name: assigned.salesperson_name,
  salesperson_email: assigned.salesperson_email,
  topics: formData.topics || ''
} }];

var items = $input.all();
var now = new Date();
var todayStr = (now.getMonth()+1) + '/' + now.getDate() + '/' + now.getFullYear();

function parseDate(s) {
  if (!s) return null;
  var p = String(s).split('/');
  if (p.length === 3) return new Date(parseInt(p[2]), parseInt(p[0])-1, parseInt(p[1]));
  return new Date(s);
}

var bookings = items.map(function(i) { return i.json; }).filter(function(b) { return b.date; });
bookings.sort(function(a, b) {
  var da = parseDate(a.date), db = parseDate(b.date);
  if (da && db && da - db !== 0) return da - db;
  return String(a.time || '').localeCompare(String(b.time || ''));
});

var weekEnd = new Date(now.getTime() + 7*24*3600000);
var todayCount = bookings.filter(function(b) { return b.date === todayStr; }).length;
var weekCount = bookings.filter(function(b) { var d = parseDate(b.date); return d && d >= now && d <= weekEnd; }).length;

var salespeople = [];
bookings.forEach(function(b) {
  var sp = b.salesperson_name || 'Unassigned';
  if (salespeople.indexOf(sp) === -1) salespeople.push(sp);
});

var spButtons = salespeople.map(function(sp) {
  var safe = sp.replace(/"/g, '&quot;');
  return '<button class="fbtn" onclick="filter(\'' + safe + '\',event)">' + sp + '</button>';
}).join('');

var rows = bookings.map(function(b) {
  var sp = b.salesperson_name || 'Unassigned';
  var isToday = (b.date === todayStr);
  return '<tr data-sp="' + sp.replace(/"/g, '') + '"' + (isToday ? ' class="today"' : '') + '>' +
    '<td>' + (b.date||'') + (isToday ? ' <span class="now">TODAY</span>' : '') + '</td>' +
    '<td>' + (b.time||'') + '</td>' +
    '<td><strong>' + (b.client_name||'') + '</strong><br><span style="color:#888;font-size:12px">' + (b.email||'') + '</span></td>' +
    '<td>' + (b.company||'') + '</td>' +
    '<td>' + (b.title||'') + '</td>' +
    '<td><span class="badge">' + sp + '</span></td>' +
    '</tr>';
}).join('');

if (!rows) rows = '<tr><td colspan="6" style="text-align:center;padding:40px;color:#999">No bookings yet</td></tr>';

var html = '<!DOCTYPE html><html><head><title>GLS Dashboard</title><meta charset="UTF-8"><meta http-equiv="refresh" content="120"><style>' +
'*{box-sizing:border-box;margin:0;padding:0}body{font-family:Arial,sans-serif;background:#f0f2f5}' +
'.hdr{background:#1a3c5e;color:#fff;padding:18px 28px;display:flex;justify-content:space-between;align-items:center}' +
'.hdr h1{font-size:20px;font-weight:bold}.hdr span{font-size:13px;opacity:.7}' +
'.stats{display:flex;gap:14px;padding:20px 28px}' +
'.card{background:#fff;border-radius:8px;padding:16px 22px;box-shadow:0 1px 4px rgba(0,0,0,.08);min-width:110px}' +
'.card .n{font-size:30px;font-weight:bold;color:#1a3c5e}.card .l{font-size:12px;color:#777;margin-top:3px}' +
'.filters{padding:0 28px 14px;display:flex;gap:8px;flex-wrap:wrap}' +
'.fbtn{padding:7px 16px;border:2px solid #1a3c5e;border-radius:20px;cursor:pointer;background:#fff;color:#1a3c5e;font-size:13px;font-family:Arial}' +
'.fbtn.active{background:#1a3c5e;color:#fff}' +
'.wrap{margin:0 28px 28px;background:#fff;border-radius:8px;box-shadow:0 1px 4px rgba(0,0,0,.08);overflow:hidden}' +
'table{width:100%;border-collapse:collapse}' +
'th{background:#eef2f7;padding:11px 14px;text-align:left;font-size:11px;color:#555;text-transform:uppercase;letter-spacing:.5px}' +
'td{padding:11px 14px;border-top:1px solid #eee;font-size:14px;vertical-align:top}' +
'tr.today td{background:#fffde7}tr.hidden{display:none}' +
'.badge{display:inline-block;padding:3px 10px;border-radius:12px;font-size:12px;background:#e3f2fd;color:#1565c0;white-space:nowrap}' +
'.now{background:#ff6f00;color:#fff;font-size:10px;padding:2px 6px;border-radius:4px;margin-left:6px;vertical-align:middle}' +
'</style></head><body>' +
'<div class="hdr"><h1>GLS Appointment Dashboard</h1><span>Auto-refreshes every 2 min &bull; ' + now.toLocaleString() + '</span></div>' +
'<div class="stats">' +
'<div class="card"><div class="n">' + bookings.length + '</div><div class="l">Total Bookings</div></div>' +
'<div class="card"><div class="n">' + todayCount + '</div><div class="l">Today</div></div>' +
'<div class="card"><div class="n">' + weekCount + '</div><div class="l">This Week</div></div>' +
'</div>' +
'<div class="filters"><button class="fbtn active" onclick="filter(\'all\',event)">All</button>' + spButtons + '</div>' +
'<div class="wrap"><table>' +
'<thead><tr><th>Date</th><th>Time</th><th>Guest</th><th>Company</th><th>Title</th><th>Assigned To</th></tr></thead>' +
'<tbody>' + rows + '</tbody></table></div>' +
'<script>function filter(sp,e){document.querySelectorAll(".fbtn").forEach(function(b){b.classList.remove("active")});e.target.classList.add("active");document.querySelectorAll("tr[data-sp]").forEach(function(r){r.classList.toggle("hidden",sp!=="all"&&r.getAttribute("data-sp")!==sp)})}<\/script>' +
'</body></html>';

return [{ json: { html: html } }];

var b = $node["Check Reminders"].all()[0].json;
var sent = (b._reminders_sent || '').split(',').filter(Boolean);
sent.push(b._type);
return [{ json: Object.assign({}, b, { _reminders_sent_new: sent.join(',') }) }];

var templates = $input.all().map(i => i.json);
var tpl = templates.find(t => t.template_name === 'reminder_auto') || {subject:'[GLS 传讯] Meeting reminder in {{_when}}',body:'Dear {{client_name}},\n\nYour meeting with GLS 传讯 at {{event_name}} is in {{_when}}.\n\n📅 {{date}} {{time}}\n📍 {{event_venue}}\n\nGLS 传讯 Team'};
var d = $node['Check Reminders'].json;
var settingsData = {};
try { var sr = await fetch('https://n8n.okahh.com/webhook/gls-settings'); settingsData = await sr.json(); } catch(e) {}
var evtName = settingsData.event_name || 'Air Cargo China 2026';
var evtDates = settingsData.event_dates || 'June 24–26, 2026';
var evtVenue = settingsData.event_venue || 'Shanghai New International Expo Centre';
var unsub = 'https://n8n.okahh.com/webhook/gls-unsubscribe?email=' + encodeURIComponent(d.email||'');
var vars = {'{{unsubscribe_link}}':unsub,'{{client_name}}':d.client_name||'','{{date}}':d.date||'','{{time}}':d.time||'','{{_when}}':d._when||'','{{company}}':d.company||'','{{salesperson_name}}':d.salesperson_name||'','{{event_name}}':evtName,'{{event_dates}}':evtDates,'{{event_venue}}':evtVenue};
var subject = tpl.subject;
var body = (tpl.body||'').replace(/\\n/g,'\n');
Object.keys(vars).forEach(k=>{subject=subject.split(k).join(vars[k]);body=body.split(k).join(vars[k]);});
if(!/<[a-z]/i.test(body)){body='<div style="font-family:Arial,sans-serif;font-size:14px;color:#222;line-height:1.8">'+body.split('\n').join('<br>')+'</div>';}
return [{json:{...d,subject:subject,body:body}}];

var templates = $input.all().map(i => i.json);
var tpl = templates.find(t => t.template_name === 'booking_received') || {subject:'[GLS 传讯] Meeting Request Received',body:'Dear {{client_name}},\n\nThank you for requesting a meeting with GLS 传讯 at {{event_name}}.\n\n📅 {{date}} {{time}}\n📍 {{event_venue}}\n\nWe will confirm your slot shortly.\n\nGLS 传讯 Team'};
var d = $node['Assign SP (Form)'].json;
var settingsData = {};
try { var sr = await fetch('https://n8n.okahh.com/webhook/gls-settings'); settingsData = await sr.json(); } catch(e) {}
var evtName = settingsData.event_name || 'Air Cargo China 2026';
var evtDates = settingsData.event_dates || 'June 24–26, 2026';
var evtVenue = settingsData.event_venue || 'Shanghai New International Expo Centre';
var unsub = 'https://n8n.okahh.com/webhook/gls-unsubscribe?email=' + encodeURIComponent(d.email||'');
var vars = {'{{unsubscribe_link}}':unsub,'{{client_name}}':d.client_name||'','{{date}}':d.date||'','{{time}}':d.time||'','{{company}}':d.company||'','{{event_name}}':evtName,'{{event_dates}}':evtDates,'{{event_venue}}':evtVenue};
var subject = tpl.subject;
var body = (tpl.body||'').replace(/\\n/g,'\n');
Object.keys(vars).forEach(k=>{subject=subject.split(k).join(vars[k]);body=body.split(k).join(vars[k]);});
if(!/<[a-z]/i.test(body)){body='<div style="font-family:Arial,sans-serif;font-size:14px;color:#222;line-height:1.8">'+body.split('\n').join('<br>')+'</div>';}
return [{json:{...d,subject:subject,body:body}}];

var assign = $node['Assign SP (Form)'].json;
var newCount = (parseInt(assign.slot_booked_count || 0)) + 1;
var cap = parseInt(assign.slot_capacity || 1);
var newStatus = newCount >= cap ? 'booked' : 'available';
return [{json:{slot_id:assign.slot_id,new_booked_count:newCount,new_status:newStatus}}];

var d = $node['Assign SP (Form)'].json;
var subject = '[GLSHK @ Air Cargo Shanghai 2026] New Booking Request — ' + (d.client_name||'Guest');
var body = '<div style="font-family:Arial,sans-serif;font-size:14px;color:#222;line-height:1.8">'
  + 'Hi Kitty,<br><br>'
  + 'A new meeting request has been submitted for Air Cargo China 2026:<br><br>'
  + '<strong>Guest:</strong> ' + (d.client_name||'') + ' (' + (d.company||'') + ')<br>'
  + '<strong>Email:</strong> ' + (d.email||'') + '<br>'
  + '<strong>Requested slot:</strong> ' + (d.date||'') + ' at ' + (d.time||'') + '<br>'
  + '<strong>Location:</strong> W5馆 展位399 / Hall W5 Booth 399, 上海新国际博览中心<br><br>'
  + '<strong>Topics of interest:</strong> ' + (d.topics||'Not specified') + '<br><br>'
  + 'Please review and assign in the GLS dashboard.</div>';
return [{json:{email:'marketing@glshk.com',subject:subject,body:body}}];
